1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a live cell alive when it has exactly 2 neighbors (survival)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
19	    expect(result).toContainEqual([1, 0]);
20	  });
21	  it("should keep a live cell alive when it has exactly 3 neighbors (survival)", () => {
22	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
23	    expect(result).toContainEqual([1, 0]);
24	  });
25	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
26	    const result = nextGeneration([[0, 1], [1, 0], [1, 1], [1, 2], [2, 1]]);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
30	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
31	    expect(result).toContainEqual([1, 1]);
32	  });
33	  it("should keep a block pattern unchanged across a generation (still life)", () => {
34	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
35	    expect(result.sort((a, b) => a[0] - b[0] || a[1] - b[1])).toEqual(
36	      [[0, 0], [0, 1], [1, 0], [1, 1]]
37	    );
38	  });
