1	const NEIGHBOR_OFFSETS: [number, number][] = [
2	  [-1, -1], [-1, 0], [-1, 1],
3	  [0, -1],           [0, 1],
4	  [1, -1],  [1, 0],  [1, 1],
5	];
6	
7	const toKey = (x: number, y: number): string => `${x},${y}`;
8	
9	export function nextGeneration(cells: [number, number][]): [number, number][] {
10	  const liveCells = new Set(cells.map(([x, y]) => toKey(x, y)));
11	
12	  const countLiveNeighbors = (x: number, y: number): number =>
13	    NEIGHBOR_OFFSETS.filter(([dx, dy]) => liveCells.has(toKey(x + dx, y + dy))).length;
14	
15	  const survivors = cells.filter(([x, y]) => {
16	    const neighbors = countLiveNeighbors(x, y);
17	    return neighbors === 2 || neighbors === 3;
18	  });
19	
20	  const deadCandidates = new Set<string>();
21	  for (const [x, y] of cells) {
22	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
23	      const key = toKey(x + dx, y + dy);
24	      if (!liveCells.has(key)) {
25	        deadCandidates.add(key);
26	      }
27	    }
28	  }
29	
30	  const born: [number, number][] = [];
31	  for (const key of deadCandidates) {
32	    const [x, y] = key.split(",").map(Number) as [number, number];
33	    if (countLiveNeighbors(x, y) === 3) {
34	      born.push([x, y]);
35	    }
36	  }
37	
38	  return [...survivors, ...born];
39	}
